# Solution: Advanced Error Handling Patterns

def circuit_breaker(func, failure_threshold=3):
    """Return a wrapper that tracks consecutive failures.
    After threshold failures, return ("circuit_open", None) without calling func."""
    state = {"failures": 0, "open": False}
    def wrapper(*args, **kwargs):
        if state["open"]:
            return ("circuit_open", None)
        try:
            result = func(*args, **kwargs)
            state["failures"] = 0
            return result
        except Exception:
            state["failures"] += 1
            if state["failures"] >= failure_threshold:
                state["open"] = True
            raise
    return wrapper

def fallback_chain(funcs, *args):
    """Try each func in order with *args. Return first success. Raise if all fail."""
    last_exception = None
    for func in funcs:
        try:
            return func(*args)
        except Exception as e:
            last_exception = e
    raise last_exception

def error_boundary(func, *args, on_error=None):
    """Call func(*args). On error, call on_error(exception) if provided, else return None."""
    try:
        return func(*args)
    except Exception as e:
        if on_error is not None:
            return on_error(e)
        return None

def validate_all(validators, value):
    """Run all validator functions on value.
    Return list of error messages from validators that raised ValueError."""
    errors = []
    for validator in validators:
        try:
            validator(value)
        except ValueError as e:
            errors.append(str(e))
    return errors

testCases.input:
def pos(n):
    if n <= 0: raise ValueError('must be positive')
def even(n):
    if n % 2 != 0: raise ValueError('must be even')
validate_all([pos, even], -3)

